<template>
    <div ref="progress" class="ui multiple progress">
        <div class="green bar">
            <div class="progress" />
        </div>
        <div class="red bar">
            <div class="progress" />
        </div>
    </div>
</template>

<script lang="ts" setup>
import "/semantic/dist/components/progress.js";

import jQuery from "jquery";
import { onBeforeUnmount, onMounted, ref, watch } from "vue";

const props = defineProps<{
    total: number;
    successCount: number;
    failedCount: number;
}>();

const progress = ref<HTMLDivElement | null>(null);

onMounted((): void => {
    jQuery(progress.value!).progress({
        showActivity: false,
        autoSuccess: false,
        label: "ratio",
        text: {
            ratio: "{value}",
        },
        total: props.total,
        value: `${props.successCount}, ${props.failedCount}`,
    });
});

onBeforeUnmount((): void => {
    jQuery(progress.value!).progress("destroy");
});

watch(
    () => props.total,
    (total: number): void => {
        jQuery(progress.value!).progress("set total", total);
    },
);

watch(
    () => props.successCount,
    (): void => {
        jQuery(progress.value!).progress("set progress", `${props.successCount}, ${props.failedCount}`);
    },
);

watch(
    () => props.failedCount,
    (): void => {
        jQuery(progress.value!).progress("set progress", `${props.successCount}, ${props.failedCount}`);
    },
);
</script>

<style scoped>
.ui.progress:last-child {
    margin-bottom: 0;
}
</style>
