<template>
    <div v-if="job" class="ui container">
        <div class="ui header">
            <i v-if="!isReady" class="fitted loading spinner icon" />
            <div class="content">
                {{ job.jid }}
            </div>
        </div>
        <div class="ui tiny message">
            <pre>salt "{{ job.tgt }}" {{ job.fun }} {{ formattedArgs }}</pre>
        </div>
        <div class="ui label">
            <i class="clock icon" />
            <span v-if="timeStamp">{{ timeStamp }}</span>
        </div>
        <div v-if="!isReady && timeRunning">Time running {{ timeRunning }}</div>
        <div class="ui basic fitted clearing segment">
            <div v-if="ishHighState" class="ui tiny right floated buttons">
                <div :class="{ green: viewMode === 'all' }" class="ui button" @click="viewMode = 'all'">All</div>
                <div :class="{ red: viewMode === 'failed' }" class="ui button" @click="viewMode = 'failed'">Failed</div>
                <div :class="{ green: viewMode === 'changed' }" class="ui button" @click="viewMode = 'changed'">
                    Changed
                </div>
                <div :class="{ blue: viewMode === 'unchanged' }" class="ui button" @click="viewMode = 'unchanged'">
                    Unchanged
                </div>
            </div>
            <div class="ui header">Minions</div>
        </div>
        <div v-if="minions.length">
            <JobResultMinionComponent
                v-for="minion in minions"
                :key="minion"
                :job-result-minion="results[minion]"
                :minion="minion"
                :view-mode="viewMode"
            />
        </div>
        <div v-else class="ui segment">
            <div class="ui container">
                <div class="ui active inverted dimmer">
                    <div class="ui text loader">Loading</div>
                </div>
            </div>
            <p />
            <p />
            <p />
        </div>
    </div>
    <div v-else>
        <div class="ui container">
            <div class="ui active inverted dimmer">
                <div class="ui text loader">Loading</div>
            </div>
        </div>
    </div>
</template>

<script lang="ts" setup>
import { computed, onBeforeUnmount, ref, watch } from "vue";

import JobResultMinionComponent from "@/components/JobResultMinion.vue";
import { useJobStore } from "@/store/jobs";
import { Job, JobDataStatus, JobResult, Minion, Out } from "@/store/jobs/types";
import { formatArgs } from "@/store/jobs/utils";

const jobStore = useJobStore();

const props = defineProps<{
    jid: string;
}>();

const timeRunning = ref<string>("");
const interval = ref<ReturnType<typeof setInterval> | undefined>(undefined);
const secondsCounter = ref<number>(0);
const viewMode = ref<string>("all");

const created = async (): Promise<void> => {
    if (job.value) {
        if (job.value.dataStatus === JobDataStatus.BASIC) {
            await jobStore.updateJobDetails(props.jid);
        }
        if (!isReady.value) {
            interval.value = setInterval(() => {
                secondsCounter.value += 1;
            }, 1000);
        }
    }
};

onBeforeUnmount((): void => {
    clearInterval(interval.value);
});

const job = computed((): Job | null => {
    const storeJob = jobStore.getJob(props.jid);
    if (storeJob) {
        return { ...storeJob };
    }
    return null;
});

const minions = computed((): Minion[] => (job.value ? job.value.minions : []));

const results = computed((): JobResult => (job.value ? job.value.results : {}));

const hasResults = computed((): boolean => Boolean(Object.keys(results.value).length));

const isReady = computed(
    (): boolean =>
        Boolean(job.value) &&
        Boolean(minions.value.length) &&
        minions.value.length === Object.keys(job.value!.resultsCodes).length,
);

const formattedArgs = computed((): string => (job.value ? formatArgs(job.value.arg) : ""));

const datetimeFormatter = new Intl.DateTimeFormat(undefined, { dateStyle: "long", timeStyle: "medium" });
const timeStamp = computed((): string | null =>
    job.value ? datetimeFormatter.format(new Date(job.value._stamp)) : null,
);

const ishHighState = computed(
    (): boolean => hasResults.value && Object.values(results.value)[0].out === Out.HIGH_STATE,
);

watch(job, async (jobNew): Promise<void> => {
    if (jobNew && jobNew.dataStatus === JobDataStatus.BASIC) {
        await jobStore.updateJobDetails(props.jid);
    }
});

watch(isReady, (value): void => {
    if (value) {
        clearInterval(interval.value);
    }
});

watch(secondsCounter, (): void => {
    if (job.value) {
        const timeString = getDateDiff(new Date(job.value._stamp));
        timeRunning.value = `${timeString} seconds`;
    }
});

const getDateDiff = (dt: Date): string => {
    const diff = Date.now() - dt.getTime();
    const totalSeconds = Math.round(diff / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds / 60) % 60);
    const seconds = totalSeconds % 60;
    const dateTimeFormat = getDateTimeFormat(totalSeconds);
    const dateDiff = Date.UTC(0, 0, 0, hours, minutes, seconds);
    return new Intl.DateTimeFormat(undefined, dateTimeFormat).format(dateDiff);
};

const getDateTimeFormat = (totalSeconds: number): Intl.DateTimeFormatOptions => {
    let dateTimeFormat: Intl.DateTimeFormatOptions;
    if (totalSeconds > 3600) {
        dateTimeFormat = {
            hour12: false,
            hour: "numeric",
            minute: "numeric",
            second: "numeric",
        };
    } else if (totalSeconds > 60) {
        dateTimeFormat = {
            minute: "numeric",
            second: "numeric",
        };
    } else {
        dateTimeFormat = {
            second: "numeric",
        };
    }
    return dateTimeFormat;
};

created();
</script>
