<template>
    <div
        v-if="jobResultMinion"
        class="ui clearing segment"
        :class="{
            green: jobResultMinion.retcode === RetCode.SUCCESS,
            red: jobResultMinion.retcode !== RetCode.SUCCESS,
        }"
    >
        <div class="ui header collapsing-header" @click="expanded = !expanded">
            <i v-if="expanded" class="caret down icon" />
            <i v-else class="caret right icon" />
            <div class="content">
                {{ minion }}
                <span v-if="isHighState">
                    <span v-if="jobResultMinion.retcode === RetCode.FAILED" class="ui red label"> Error </span>
                    <span v-else-if="jobResultMinion.retcode === RetCode.ERROR" class="ui red label">
                        {{ failedLines }} failed
                    </span>
                </span>
            </div>
            <div v-if="isHighState" class="ui top right attached label">{{ totalLines }} states</div>
        </div>
        <div v-if="expanded">
            <div v-if="jobResultMinion.retcode === RetCode.FAILED">
                <div>
                    <div class="ui error message">
                        <ValueDisplay :value="jobResultMinion.return" />
                    </div>
                </div>
            </div>
            <div v-else>
                <table v-if="isHighState" class="ui very basic very compact table">
                    <HighStateResultGroup
                        v-for="(results, index) in groupedResults"
                        :key="index"
                        :sls="results.sls"
                        :results="results.results"
                        :view-mode="viewMode"
                    />
                </table>
                <ValueDisplay v-else :value="jobResultMinion.return" />
            </div>
        </div>
    </div>
    <div v-else class="ui segment">
        <div class="ui header">
            <i class="loading spinner icon" />
            <div class="content">
                {{ minion }}
            </div>
        </div>
    </div>
</template>

<script lang="ts" setup>
import { computed, onMounted, ref, watch } from "vue";

import HighStateResultGroup from "@/components/HighStateResultGroup.vue";
import ValueDisplay from "@/components/ValueDisplay.vue";
import { HighStateResult, JobResultHighState, JobResultMinion, Out, RetCode } from "@/store/jobs/types";

interface GroupResult {
    sls: string;
    results: HighStateResult[];
}

const props = withDefaults(
    defineProps<{
        jobResultMinion?: JobResultMinion;
        minion: string;
        viewMode?: string;
    }>(),
    {
        jobResultMinion: undefined,
        viewMode: "all",
    },
);

const expanded = ref(false);

onMounted((): void => {
    if (props.jobResultMinion?.retcode === RetCode.FAILED) {
        expanded.value = true;
    }
});

watch(
    () => props.viewMode,
    (value): void => {
        if (value === "failed" && !expanded.value) {
            expanded.value = true;
        }
    },
);

const isHighState = computed(
    (): boolean => props.jobResultMinion?.out === Out.HIGH_STATE && typeof props.jobResultMinion?.return === "object",
);

const totalLines = computed((): number => {
    if (isHighState.value && props.jobResultMinion) {
        return Object.keys(props.jobResultMinion.return).length;
    }
    return 1;
});

const successLines = computed((): number => {
    if (isHighState.value && props.jobResultMinion) {
        return Object.values(props.jobResultMinion.return).filter((highStateResult) => highStateResult.result).length;
    }
    return props.jobResultMinion?.success ? 1 : 0;
});

const failedLines = computed((): number => totalLines.value - successLines.value);

const sortedResults = computed((): HighStateResult[] => {
    const jobs = props.jobResultMinion?.return as JobResultHighState;
    return Object.values(jobs).sort((a: HighStateResult, b: HighStateResult) => a.__run_num__ - b.__run_num__);
});

const groupedResults = computed((): GroupResult[] => {
    const groupsResults: GroupResult[] = [];
    sortedResults.value.forEach((result: HighStateResult) => {
        if (!groupsResults.length || groupsResults[groupsResults.length - 1].sls !== result.__sls__) {
            groupsResults.push({
                sls: result.__sls__,
                results: [],
            });
        }
        groupsResults[groupsResults.length - 1].results.push(result);
    });
    return groupsResults;
});
</script>

<style scoped>
.collapsing-header {
    cursor: pointer;
}
</style>
