import { defineStore } from "pinia";

import { Minion } from "@/store/jobs/types";

export const useWheelStore = defineStore("wheel", {
    state: () => ({
        minionsRejected: [] as string[],
        minionsDenied: [] as string[],
        minionsPre: [] as string[],
        minions: [] as string[],
    }),
    actions: {
        setMinions(minions: Minion[]): void {
            this.minions = minions;
        },
        setMinionsRejected(minions: Minion[]): void {
            this.minionsRejected = minions;
        },
        setMinionsDenied(minions: Minion[]): void {
            this.minionsDenied = minions;
        },
        setMinionsPre(minions: Minion[]): void {
            this.minionsPre = minions;
        },
    },
});
