<template>
    <Backdrop />
    <div class="ui text container">
        <div class="ui scrolling middle aligned center aligned grid">
            <div class="row">
                <div class="column">
                    <div class="ui inverted logo header">
                        <img src="/src/assets/img/logo.png" alt="SaltStack GUI Logo" />
                        <div class="content">Saltstack GUI</div>
                    </div>
                    <form class="ui large form" :class="{ error: error }" @submit.prevent="login">
                        <div class="ui attached error message">
                            {{ error }}
                        </div>
                        <div class="ui stacked very padded segment" :class="{ attached: error }">
                            <div class="ui header">Login</div>
                            <div class="field">
                                <div class="ui left icon input">
                                    <i class="user icon" />
                                    <label for="username" class="transition hidden">Username</label>
                                    <input id="username" v-model="username" type="text" placeholder="Username" />
                                </div>
                            </div>
                            <div class="field">
                                <div class="ui left icon input">
                                    <i class="lock icon" />
                                    <label for="password" class="transition hidden">Password</label>
                                    <input
                                        id="password"
                                        v-model="password"
                                        type="password"
                                        autocomplete="off"
                                        placeholder="Password"
                                    />
                                </div>
                            </div>
                            <button
                                type="submit"
                                class="ui fluid large submit button primary"
                                :class="{ loading: busy }"
                                :disabled="busy"
                            >
                                Sign in
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    </div>
</template>

<script lang="ts" setup>
import { ref } from "vue";
import { useRouter } from "vue-router";

import { api, HTTPError } from "@/api";
import Backdrop from "@/components/Backdrop.vue";
import { useRootStore } from "@/store";
import { getBaseInfo } from "@/store/utils";

const rootStore = useRootStore();
const router = useRouter();

const username = ref<string>("");
const password = ref<string>("");
const busy = ref<boolean>(false);
const error = ref<null | string>(null);

const login = async (): Promise<void> => {
    busy.value = true;
    try {
        await api.login(username.value, password.value, "pam");
    } catch (err) {
        busy.value = false;
        if (err instanceof HTTPError && err.status === 401) {
            error.value = "Invalid credentials";
        } else {
            console.error("LoginError", err);
            error.value = (err as Error).toString();
        }
        return;
    }

    busy.value = false;
    rootStore.setLoggedIn();
    getBaseInfo();
    await router.push({ name: "jobs" });
};
</script>
