import { defineStore } from "pinia";

import { api } from "@/api";
import {
    Jid,
    Job,
    JobDataStatus,
    JobResultMinion,
    Jobs,
    Minion,
    RetCode,
    RunnerJobsListJobResponse,
} from "@/store/jobs/types";
import { convertJobBaseResponseToJob } from "@/store/jobs/utils";

export const useJobStore = defineStore("jobs", {
    state: () => ({
        jobs: {} as Jobs,
    }),
    getters: {
        jobListRunning(): Job[] {
            return this.jobList.filter((job: Job) => {
                const minionCount = job.minions.length;
                const resultCount = Object.keys(job.resultsCodes).length;
                return resultCount < minionCount;
            });
        },
        jobList(): Job[] {
            return Object.keys(this.jobs)
                .map((jid: Jid) => {
                    const obj = this.jobs[jid];
                    obj.jid = jid;
                    return obj;
                })
                .sort((a: Job, b: Job) => Number(b.jid) - Number(a.jid));
        },
        getJob:
            (state) =>
            (jid: Jid): Job | undefined =>
                state.jobs[jid],
    },
    actions: {
        setMinions({ jid, minions }: { jid: Jid; minions: Minion[] }): void {
            this.jobs[jid].minions = minions;
        },
        addNewJob(job: Job): void {
            this.jobs[job.jid] = job;
        },
        addJobResult({ resultMinion, minion, jid }: { jid: Jid; resultMinion: JobResultMinion; minion: Minion }): void {
            if (!this.jobs[jid]) {
                console.error(`Trying to add job result with jid: ${jid}, but job does not exists`);
                return;
            }
            if (!this.jobs[jid].results) {
                this.jobs[jid].results = {};
            }
            this.jobs[jid].results[minion] = resultMinion;

            this.addJobResultCodes({ jid, retCode: resultMinion.retcode, minion });
            this.addMinion({ jid, minion });
        },
        updateJobs(jobs: Jobs): void {
            Object.entries(jobs).forEach((entry) => {
                const [jid, job] = entry;
                this.jobs[jid] = job;
            });
        },
        async updateJobDetails(jid: Jid): Promise<boolean> {
            this.setJobDataStatus({ jid, dataStatus: JobDataStatus.LOADING_DETAILS });
            let responseJob: RunnerJobsListJobResponse | void | null = null;
            try {
                responseJob = await api.getRunnerJobsListJob(jid);
            } catch (err) {
                this.setJobDataStatus({ jid, dataStatus: JobDataStatus.BASIC });
                console.warn(err);
            }
            if (responseJob) {
                const jobInfo: Job = convertJobBaseResponseToJob(responseJob, jid, {
                    Minions: responseJob.Minions,
                    Result: responseJob.Result,
                });
                if (jobInfo.minions.length) {
                    this.setMinions({ jid, minions: jobInfo.minions });
                }
                if (jobInfo.results) {
                    Object.keys(jobInfo.results).forEach((minion: Minion) => {
                        const resultMinion: JobResultMinion = jobInfo.results[minion];
                        this.addJobResult({ jid, resultMinion, minion });
                    });
                }
                this.setJobDataStatus({ jid, dataStatus: JobDataStatus.FULL });
                return true;
            }
            this.setJobDataStatus({ jid, dataStatus: JobDataStatus.BASIC });
            return false;
        },
        addMinion({ jid, minion }: { jid: Jid; minion: Minion }): void {
            if (this.jobs[jid].minions.indexOf(minion) === -1) {
                this.jobs[jid].minions.push(minion);
            }
        },
        setJobDataStatus({ jid, dataStatus }: { jid: Jid; dataStatus: JobDataStatus }): void {
            this.jobs[jid].dataStatus = dataStatus;
        },
        addJobResultCodes({ jid, retCode, minion }: { jid: Jid; retCode: RetCode; minion: Minion }): void {
            this.jobs[jid].resultsCodes[minion] = retCode;
        },
    },
});
