<template>
    <form class="ui form" @submit.prevent="execute">
        <div class="inline fields">
            <div class="field">
                <div class="ui toggle checkbox">
                    <input id="toggle-state" ref="stateToggle" v-model="runState" class="ui checkbox" type="checkbox" />
                    <label for="toggle-state">State?</label>
                </div>
            </div>
            <div class="field">
                <label for="target" style="display: none">Target</label>
                <input id="target" v-model="target" placeholder="Target" />
            </div>
            <div class="field">
                <label for="state" style="display: none">
                    <span v-if="runState">State</span>
                    <span v-else>Command</span>
                </label>
                <input id="state" v-model="state" :placeholder="runState ? 'State' : 'Command'" />
            </div>
            <div v-show="runState" class="field">
                <div class="ui toggle checkbox">
                    <input id="toggle-test" v-model="test" type="checkbox" />
                    <label for="toggle-test">Test</label>
                </div>
            </div>
            <div class="field">
                <button type="submit" class="ui button">Execute</button>
            </div>
        </div>
    </form>
</template>

<script lang="ts" setup>
import "/semantic/dist/components/checkbox.js";

import jQuery from "jquery";
import { onMounted, ref } from "vue";
import { useRouter } from "vue-router";

import { api, HTTPError } from "@/api";
import { ExecuteResult } from "@/store/local/types";

const router = useRouter();

const stateToggle = ref(null);
const toggleTest = ref(null);

const runState = ref(true);
const target = ref("");
const state = ref("");
const test = ref(false);

onMounted((): void => {
    jQuery(stateToggle.value!).checkbox();
    jQuery(toggleTest.value!).checkbox();
});

const execute = async (): Promise<void> => {
    let result: void | ExecuteResult;
    try {
        if (runState.value) {
            result = await api.runState(target.value, state.value, "", test.value);
        } else {
            result = await api.execute(target.value, state.value, "");
        }
    } catch (error) {
        console.log("JobRunner", error);
        if (error instanceof HTTPError) {
            console.error(error.message);
        }
        return;
    }

    if (result && Object.keys(result).length) {
        await router.push({ name: "job", params: { jid: result.jid } });
    }
};
</script>

<style scoped>
.ui.form {
    margin-bottom: 0;
    margin-left: 4em;
}

.ui.form .inline.fields {
    margin: 0;
}
</style>
