import { defineStore } from "pinia";

import { Perms } from "./types";

export const useRootStore = defineStore("root", {
    state: () => ({
        version: import.meta.env.PACKAGE_VERSION,
        loggedIn: false,
        user: window.sessionStorage.getItem("user") || "",
        perms: JSON.parse(window.sessionStorage.getItem("perms") || "{}") as Perms,
    }),
    getters: {
        hasPerm:
            (state) =>
            ({ module, perm }: { module: string; perm: string }) => {
                if (module in state.perms && Array.isArray(state.perms[module])) {
                    return (state.perms[module] as string[]).includes(perm);
                }
                return false;
            },
    },
    actions: {
        setUser(user: string) {
            this.user = user;
            window.sessionStorage.setItem("user", user);
        },
        setPerms(perms: Perms) {
            this.perms = perms;
            window.sessionStorage.setItem("perms", JSON.stringify(perms));
        },
        setLoggedIn() {
            this.loggedIn = true;
        },
        setLoggedOut() {
            this.loggedIn = false;
            window.sessionStorage.removeItem("user");
            window.sessionStorage.removeItem("perms");
        },
    },
});
