<template>
    <tr v-if="matchViewMode">
        <td class="top aligned collapsing clickable" @click.stop="expanded = !expanded">
            <i v-if="expanded" class="caret down icon" />
            <i v-else class="caret right icon" />
        </td>
        <td>
            <div class="clickable" @click.stop="expanded = !expanded">
                <div class="ui small left floated header">
                    {{ sls }}
                </div>
                <i v-if="success" class="green check icon" />
                <span v-if="failedLines" class="ui mini red label">{{ failedLines }} failed</span>
                <span v-if="unchangedLines" class="ui mini blue label label">{{ unchangedLines }} unchanged</span>
                <span v-if="changedLines" class="ui mini green label">{{ changedLines }} changed</span>
                <div class="total-duration">
                    {{ totalDuration }} ms
                    <i class="clock icon" :class="durationColorClass" />
                </div>
            </div>
            <table v-if="expanded" class="ui very basic very compact table">
                <HighStateResultComponent
                    v-for="resultItem in resultsFiltered"
                    :key="resultItem.__run_num__"
                    :result-item="resultItem"
                />
            </table>
        </td>
    </tr>
</template>

<script lang="ts" setup>
import { computed, ref } from "vue";

import HighStateResultComponent from "@/components/HighStateResult.vue";
import { HighStateResult } from "@/store/jobs/types";

const props = withDefaults(
    defineProps<{
        sls: string;
        results: HighStateResult[];
        viewMode?: string;
    }>(),
    { viewMode: "all" },
);

const expanded = ref<boolean>(false);

const resultsFiltered = computed((): HighStateResult[] => props.results.filter(matchViewModeResult));

const matchViewMode = computed(
    (): boolean =>
        props.viewMode === "all" ||
        (props.viewMode === "failed" && Boolean(failedLines.value)) ||
        (props.viewMode === "changed" && Boolean(changedLines.value)) ||
        (props.viewMode === "unchanged" && Boolean(unchangedLines.value)),
);

const totalLines = computed((): number => props.results.length);

const failedLines = computed(
    (): number => props.results.filter((highStateResult) => highStateResult.result === false).length,
);

const changedLines = computed(
    (): number =>
        props.results.filter(
            (highStateResult) => highStateResult.changes && Object.keys(highStateResult.changes).length,
        ).length,
);

const unchangedLines = computed(
    (): number => props.results.filter((highStateResult) => highStateResult.result === null).length,
);

const successLines = computed(
    (): number => props.results.filter((highStateResult) => highStateResult.result === true).length,
);

const success = computed((): boolean => successLines.value === totalLines.value);

const totalDuration = computed((): number =>
    Math.round(props.results.reduce((previousValue, highStateResult) => previousValue + highStateResult.duration, 0)),
);

const durationColorClass = computed((): string => {
    if (totalDuration.value > 1000) {
        return "red";
    }
    if (totalDuration.value > 500) {
        return "orange";
    }
    if (totalDuration.value > 100) {
        return "yellow";
    }
    return "";
});

const matchViewModeResult = (highStateResult: HighStateResult): boolean =>
    props.viewMode === "all" ||
    (props.viewMode === "failed" && highStateResult.result === false) ||
    (props.viewMode === "changed" && highStateResult.changes && Boolean(Object.keys(highStateResult.changes).length)) ||
    (props.viewMode === "unchanged" && highStateResult.result === null);
</script>

<style scoped>
.ui.header {
    margin-bottom: 0;
}

.clickable {
    cursor: pointer;
}

.collapsing {
    width: 1px;
    white-space: nowrap;
}

.total-duration {
    float: right;
}
</style>
