<template>
    <tr class="item" @click.stop>
        <td class="top aligned collapsing" :class="{ clickable: canExpand }" @click.stop="expanded = !expanded">
            <i v-if="!canExpand" class="white icon" />
            <i v-else-if="expanded" class="caret down icon" />
            <i v-else class="caret right icon" />
        </td>
        <td>
            <div :class="{ clickable: canExpand }" @click.stop="expanded = !expanded">
                <div class="ui small left floated header">
                    {{ title }}
                </div>
                <i v-if="resultItem.__state_ran__ === false" class="minus icon" />
                <i v-else-if="resultItem.result === true" class="green check icon" />
                <i v-else-if="resultItem.result === null" class="blue circle icon" />
                <i v-else-if="!resultItem.result" class="red circle icon" />
                <div style="float: right">
                    {{ totalDuration }} ms
                    <i class="clock icon" :class="durationColorClass" />
                </div>
                <div class="description">
                    Name: {{ resultItem.name }}<br />
                    <ValueDisplay v-if="multiLineComment" :value="resultItem.comment" />
                    <span v-else>{{ resultItem.comment }}<br /></span>
                </div>
                <div v-if="canExpand && expanded" class="extra" @click.stop>
                    <div v-if="resultItem.changes && Object.keys(resultItem.changes).length">
                        <ValueDisplay title="Changes" :value="resultItem.changes" />
                    </div>
                    <div v-if="resultItem.pchanges && Object.keys(resultItem.pchanges).length">
                        <ValueDisplay title="P Changes" :value="resultItem.pchanges" />
                    </div>
                </div>
            </div>
        </td>
    </tr>
</template>

<script lang="ts" setup>
import { computed, ref } from "vue";

import ValueDisplay from "@/components/ValueDisplay.vue";
import { HighStateResult } from "@/store/jobs/types";

const props = defineProps<{
    resultItem: HighStateResult;
}>();

const expanded = ref<boolean>(false);

const title = computed((): string => {
    const resultItem = props.resultItem as HighStateResult;
    return resultItem.__id__ || resultItem.__sls__;
});

const canExpand = computed((): boolean => {
    const resultItem = props.resultItem as HighStateResult;
    return Boolean(
        (resultItem.changes && Object.keys(resultItem.changes).length) ||
            (resultItem.pchanges && Object.keys(resultItem.pchanges).length),
    );
});

const multiLineComment = computed((): boolean => {
    const resultItem = props.resultItem as HighStateResult;
    return Boolean(resultItem.comment) && resultItem.comment.includes("\n");
});

const totalDuration = computed((): number => {
    const resultItem = props.resultItem as HighStateResult;
    return Math.round(resultItem.duration);
});

const durationColorClass = computed((): string => {
    const resultItem = props.resultItem as HighStateResult;
    if (resultItem.duration > 1000) {
        return "red";
    }
    if (resultItem.duration > 500) {
        return "orange";
    }
    if (resultItem.duration > 100) {
        return "yellow";
    }
    return "";
});
</script>

<style scoped>
.clickable {
    cursor: pointer;
}

.left.floated.header {
    margin-bottom: 0;
}

.description {
    clear: both;
    max-width: 50vw;
    overflow-x: auto;
}

.ui.table tr .ui.table tr td {
    border-top: 1px solid rgba(34, 36, 38, 0.1);
}
</style>
