<template>
    <pre v-if="isDiff"><code ref="code" class="diff">{{ value }}</code></pre>
    <pre v-else-if="isJson"><code ref="code" class="json">{{ asJsonString }}</code></pre>
    <pre v-else>{{ value }}</pre>
</template>

<script lang="ts" setup>
import "@/assets/css/hljs.css";

import hljs from "highlight.js/lib/core";
import diff from "highlight.js/lib/languages/diff";
import json from "highlight.js/lib/languages/json";
import { computed, onMounted, ref } from "vue";

hljs.registerLanguage("diff", diff);
hljs.registerLanguage("json", json);

const code = ref<HTMLElement | null>(null);

const props = withDefaults(
    defineProps<{
        codeKey: string;
        value: string | number | boolean | object;
    }>(),
    {
        codeKey: "",
    },
);

onMounted((): void => {
    if (code.value) {
        hljs.highlightElement(code.value);
    }
});

const isDiff = computed(
    (): boolean =>
        props.codeKey === "diff" &&
        typeof props.value === "string" &&
        props.value.indexOf("--- ") >= 0 &&
        props.value.indexOf("+++ ") >= 0 &&
        props.value.indexOf("@@ ") >= 0,
);

const isJson = computed((): boolean => typeof props.value === "object");

const asJsonString = computed((): string => JSON.stringify(props.value, null, 2));
</script>

<style scoped>
pre {
    max-width: 50vw;
    overflow-x: auto;
}
</style>
