import { api } from "@/api";
import { startConsumingEvents } from "@/store/events/consume-events";
import { useJobStore } from "@/store/jobs";
import {
    Jid,
    Job,
    JobBaseResponse,
    Jobs,
    RunnerJobsActiveResponse,
    RunnerJobsListJobsResponse,
} from "@/store/jobs/types";
import { convertJobBaseResponseToJob } from "@/store/jobs/utils";
import { useWheelStore } from "@/store/wheel";
import { WheelKeyListAllResponse } from "@/store/wheel/types";

export const getBaseInfo = (): void => {
    const wheelStore = useWheelStore();
    const jobStore = useJobStore();

    // Get all available minions
    api.getWheelKeyListAll().then((result: WheelKeyListAllResponse | void): void => {
        if (result) {
            const data = result.data.return;
            wheelStore.setMinions(data.minions);
            wheelStore.setMinionsRejected(data.minions_rejected);
            wheelStore.setMinionsDenied(data.minions_denied);
            wheelStore.setMinionsPre(data.minions_pre);
        }
    });

    const filterAndConvertJobs = (jobs: Record<Jid, JobBaseResponse>): Jobs => {
        return Object.keys(jobs).reduce((result: Jobs, jid: Jid) => {
            const job = jobs[jid];
            if (!job.Function.startsWith("saltutil.")) {
                result[jid] = convertJobBaseResponseToJob(job, jid);
            }
            return result;
        }, {} as Jobs);
    };

    // Get running jobs
    const refreshActiveJobs = () => {
        api.getRunnerJobsActive().then(async (jobs: RunnerJobsActiveResponse | void): Promise<void> => {
            if (jobs) {
                const filteredJobs = filterAndConvertJobs(jobs);

                await Promise.all(
                    Object.values(filteredJobs).map(async (job: Job) => {
                        await jobStore.updateJobDetails(job.jid);
                    }),
                );

                jobStore.updateJobs(filteredJobs);
            }
        });
    };

    refreshActiveJobs();

    // Get today's jobs
    api.getRunnerJobsListJobs().then((jobs: RunnerJobsListJobsResponse | void): void => {
        if (jobs) {
            const filteredJobs = filterAndConvertJobs(jobs);

            jobStore.updateJobs(filteredJobs);
        }
    });

    startConsumingEvents();
};
