<template>
    <div v-if="loggedIn" class="ui fixed secondary pointing menu">
        <RouterLink :exact="true" :to="{ path: '/' }" class="menu-home item"> Minions </RouterLink>
        <RouterLink :to="{ path: '/jobs' }" class="item"> Jobs </RouterLink>
        <div :class="{ grey: !jobListRunning.length }" class="item">
            <span class="ui grey text"> Running Jobs {{ jobListRunning.length }} </span>
        </div>
        <JobRunner />
        <div class="right menu">
            <div class="item">
                <span class="ui grey text"> Welcome {{ userCapFirst }} </span>
            </div>
            <a class="ui item" @click="logout">
                <i class="power off icon" />
                Logout
            </a>
        </div>
    </div>
    <div v-if="isBooted" class="main content">
        <router-view />
    </div>
    <div v-else class="ui container">
        <Backdrop v-if="!loggedIn" />
        <div class="ui active inverted dimmer">
            <div class="ui text loader">Loading</div>
        </div>
    </div>
</template>

<script lang="ts" setup>
import { computed, ref } from "vue";
import { useRouter } from "vue-router";

import { api } from "@/api";
import Backdrop from "@/components/Backdrop.vue";
import JobRunner from "@/components/JobRunner.vue";
import { useRootStore } from "@/store";
import { useJobStore } from "@/store/jobs";
import { Job } from "@/store/jobs/types";
import { getBaseInfo } from "@/store/utils";

const isBooted = ref(false);
const router = useRouter();

const rootStore = useRootStore();
const jobStore = useJobStore();
const loggedIn = computed((): boolean => rootStore.loggedIn);
const jobListRunning = computed((): Job[] => jobStore.jobListRunning);

const userCapFirst = computed((): string => {
    return rootStore.user.length ? rootStore.user.charAt(0).toUpperCase() + rootStore.user.slice(1) : rootStore.user;
});

const login = async (): Promise<void> => {
    let isAuthenticated = false;
    try {
        isAuthenticated = await api.isAuthenticated();
    } catch (err) {
        console.error("isAuthenticated error", err);
        isBooted.value = true;
        return;
    }

    if (isAuthenticated) {
        rootStore.setLoggedIn();
        getBaseInfo();
        isBooted.value = true;
    } else {
        isBooted.value = true;
        await router.push({ name: "login" });
    }
};

const logout = async (): Promise<void> => {
    await api.logout();
    rootStore.setLoggedOut();
    await router.push({ name: "login" });
};

login();
</script>

