<template>
    <RouterLink v-slot="{ navigate }" custom :to="{ name: 'job', params: { jid: job.jid } }">
        <tr :class="{ active: jobStatus === JobStatus.RUNNING }" @click="navigate">
            <td>
                <div>
                    <i v-if="job.dataStatus === JobDataStatus.BASIC" class="refresh icon" @click.stop="updateStatus" />
                    <i v-else-if="job.dataStatus === JobDataStatus.LOADING_DETAILS" class="loading refresh icon" />
                    <i v-else-if="jobStatus === JobStatus.RUNNING" class="loading spinner icon" />
                    <i v-else-if="jobStatus === JobStatus.SUCCESS" class="green check icon" />
                    <i v-else-if="jobStatus === JobStatus.FAILED" class="red x icon" />
                </div>
            </td>
            <td>{{ job.jid }}</td>
            <td>
                <div class="single line" style="max-width: 30em; overflow: hidden; text-overflow: ellipsis">
                    {{ job.fun }}
                    <span style="color: #999">{{ formattedArgs }}</span>
                </div>
            </td>
            <td>{{ timeStamp }}</td>
            <td>{{ job.tgt }}</td>
            <td>
                <JobProgress
                    v-if="jobStatus !== JobStatus.UNKNOWN"
                    :total="minionCount"
                    :success-count="successCount"
                    :failed-count="failedCount"
                />
            </td>
        </tr>
    </RouterLink>
</template>

<script lang="ts" setup>
import { computed } from "vue";

import JobProgress from "@/components/JobProgress.vue";
import { useJobStore } from "@/store/jobs";
import { Job, JobDataStatus, JobStatus, RetCode } from "@/store/jobs/types";
import { calculateJobStatus, formatArgs } from "@/store/jobs/utils";

const jobStore = useJobStore();

const props = defineProps<{
    job: Job;
}>();

const jobStatus = computed((): JobStatus => calculateJobStatus(props.job));

const minionCount = computed((): number => props.job.minions.length);

const successCount = computed(
    (): number =>
        Object.values(props.job.resultsCodes).filter((retCode: RetCode) => retCode === RetCode.SUCCESS).length,
);

const failedCount = computed(
    (): number =>
        Object.values(props.job.resultsCodes).filter((retCode: RetCode) => retCode !== RetCode.SUCCESS).length,
);

const formattedArgs = computed((): string => formatArgs(props.job.arg));

const dateTimeFormatter = new Intl.DateTimeFormat(undefined, { timeStyle: "medium" });
const timeStamp = computed((): string => dateTimeFormatter.format(new Date(props.job._stamp)));

const updateStatus = (): void => {
    jobStore.updateJobDetails(props.job.jid);
};
</script>
