<template>
    <div>
        <div class="ui basic fitted clearing segment">
            <div v-if="isObject && displayOptions.length > 1" class="ui right floated mini icon buttons">
                <div
                    v-if="allowDataTable"
                    class="ui button"
                    :class="{ blue: activeDataDisplay === DataDisplay.DATA_TABLE }"
                    @click.stop="activeDataDisplay = DataDisplay.DATA_TABLE"
                >
                    <i class="table icon" />
                </div>
                <div
                    class="ui button"
                    :class="{ blue: activeDataDisplay === DataDisplay.DEFINITION_TABLE }"
                    @click.stop="activeDataDisplay = DataDisplay.DEFINITION_TABLE"
                >
                    <i class="th list icon" />
                </div>
                <div
                    class="ui button"
                    :class="{ blue: activeDataDisplay === DataDisplay.JSON }"
                    @click.stop="activeDataDisplay = DataDisplay.JSON"
                >
                    { }
                </div>
            </div>
            <div v-if="title" class="ui tiny header">
                {{ title }}
            </div>
        </div>
        <div v-if="isSimpleValue">
            <Highlight :value="value" />
        </div>
        <div v-else-if="isArray">
            <pre v-for="(item, index) in value" :key="index">{{ item }}</pre>
        </div>
        <div v-else-if="isObject">
            <div v-if="isEmpty">NO RESULTS</div>
            <div v-else-if="activeDataDisplay === DataDisplay.DATA_TABLE">
                <table class="ui compact table">
                    <thead>
                        <tr>
                            <th />
                            <th v-for="(key, index) in dataTableHeader" :key="index">
                                {{ key }}
                            </th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr v-for="(row, rowIndex) in value" :key="rowIndex">
                            <td>
                                <b>{{ rowIndex }}</b>
                            </td>
                            <td v-for="(columnValue, colIndex) in row" :key="colIndex" class="collapsing">
                                {{ columnValue }}
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            <div v-else-if="activeDataDisplay === DataDisplay.DEFINITION_TABLE">
                <table class="ui compact definition table">
                    <tbody>
                        <tr v-for="(rowValue, key) in value" :key="key">
                            <td class="collapsing">
                                <b>{{ key }}</b>
                            </td>
                            <td>
                                <Highlight :code-key="key" :value="rowValue" />
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>
            <Highlight v-else :value="value" />
        </div>
    </div>
</template>

<script lang="ts" setup>
import { computed, ref } from "vue";

import Highlight from "@/components/Highlight.vue";
import { AnyObject } from "@/store/types";

enum DataDisplay {
    JSON = "JSON",
    DATA_TABLE = "DATA_TABLE",
    DEFINITION_TABLE = "DEFINITION_TABLE",
}

const props = withDefaults(
    defineProps<{
        title?: string;
        value: boolean | string | number | object;
    }>(),
    {
        title: "",
    },
);

const activeDataDisplay = ref<DataDisplay>(DataDisplay.JSON);

const isSimpleValue = computed((): boolean => typeof props.value !== "object");

const isArray = computed((): boolean => Array.isArray(props.value));

const isObject = computed((): boolean => typeof props.value === "object" && !isArray.value);

const isEmpty = computed((): boolean => {
    if (typeof props.value === "object") {
        return !Object.keys(props.value).length;
    }
    return !props.value;
});

const displayOptions = computed((): string[] => {
    if (!isObject.value) {
        return [];
    }
    const displayOptionList = [DataDisplay.JSON, DataDisplay.DEFINITION_TABLE];
    if (isEmpty.value) {
        return [];
    }
    if (allowDataTable.value) {
        displayOptionList.push(DataDisplay.DATA_TABLE);
    }
    return displayOptionList;
});

const allSimpleValues = computed((): boolean => {
    if (!isObject.value) {
        return false;
    }
    return Object.values(props.value).every((value: unknown) => typeof value !== "object" || Array.isArray(value));
});

const allowDataTable = computed((): boolean => {
    if (!isObject.value) {
        return false;
    }
    let columns = "";
    return Object.values(props.value).every((change: unknown) => {
        if (typeof change !== "object" || change === null) {
            return false;
        }
        if (!columns.length) {
            columns = Object.keys(change as AnyObject).join("");
            return true;
        }
        return Object.keys(change as AnyObject).join("") === columns;
    });
});

const dataTableHeader = computed((): string[] => {
    if (allowDataTable.value) {
        const value = Object.values(props.value as AnyObject)[0] as AnyObject;
        return Object.keys(value);
    }
    return [];
});

if (allSimpleValues.value) {
    activeDataDisplay.value = DataDisplay.DEFINITION_TABLE;
} else if (allowDataTable.value) {
    activeDataDisplay.value = DataDisplay.DATA_TABLE;
}
</script>

<style scoped>
td > pre {
    margin: 0;
}
</style>
