import { useJobStore } from "@/store/jobs";
import { Jid, JobResultMinion, JobReturn, Minion, Out, RetCode } from "@/store/jobs/types";

export interface SaltJobRetResponse {
    out?: Out;
    _stamp: string;
    cmd: string;
    fun: string;
    fun_args: string[];
    id: Minion;
    jid: Jid;
    retcode: RetCode;
    return: JobReturn;
    success: boolean;
}

export const saltJobRetListener = (tag: string, data: SaltJobRetResponse): void => {
    if (!data.fun.startsWith("saltutil.")) {
        const minion: Minion = tag.split("/")[4];
        const resultMinion: JobResultMinion = {
            out: data.out,
            retcode: data.retcode,
            return: data.return,
            success: data.success,
        };
        const jobStore = useJobStore();
        jobStore.addJobResult({
            jid: data.jid,
            resultMinion,
            minion,
        });
    }
};
