import { useJobStore } from "@/store/jobs";
import { Jid, Job, JobArgument, JobDataStatus, Minion } from "@/store/jobs/types";

export interface SaltJobNewResponse {
    _stamp: string;
    arg: JobArgument[];
    fun: string;
    jid: Jid;
    minions: Minion[];
    missing: string[];
    tgt: string;
    tgt_type: string;
    user: string;
}

export const convertToJob = (anyJob: SaltJobNewResponse): Job => ({
    _stamp: anyJob._stamp,
    arg: anyJob.arg,
    fun: anyJob.fun,
    jid: anyJob.jid,
    dataStatus: JobDataStatus.FULL,
    minions: anyJob.minions,
    missing: anyJob.missing,
    tgt: anyJob.tgt,
    tgtType: anyJob.tgt_type,
    user: anyJob.user,
    resultsCodes: {},
    results: {},
});

export const saltJobNewListener = (tag: string, data: SaltJobNewResponse): void => {
    if (!data.fun.startsWith("saltutil.")) {
        const jobStore = useJobStore();
        jobStore.addNewJob(convertToJob(data));
    }
};
